Additionally, my method also fetches the user that issued the transaction (I use the Flask plugin).

    def changeset(self, version, previous, transaction):
        if not previous and version.operation_type != Operation.INSERT:
            return {}

        data = {
            'updated_by': transaction.user
        }

        for key in inspect(self.__class__).columns.keys():
            if is_internal_column(self, key):
                continue
            if not previous:
                old = None
            else:
                old = getattr(previous, key)
            new = getattr(version, key)
            if old != new:
                data[key] = [old, new]

        return data

